using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFormattedNumber()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.StartsWith("(555)", result);
        Assert.EndsWith("4567", result);
        Assert.AreEqual("(555) 123-4567", result);
    }

    [TestMethod]
    [DataRow("0000000000", "(000) 000-0000")]
    [DataRow("9876543210", "(987) 654-3210")]
    public void FormatPhoneNumber_VariousInputs_ReturnsExpectedFormat(string digits, string expected)
    {
        var result = _formatter.FormatPhoneNumber(digits);

        Assert.StartsWith("(", result);
        Assert.Contains(") ", result);
        Assert.Contains("-", result);
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatPhoneNumber_NullInput_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _formatter.FormatPhoneNumber(null!));
        Assert.AreEqual("digits", ex.ParamName);
    }

    [TestMethod]
    [DataRow("123")]
    [DataRow("12345678901")]
    [DataRow("")]
    public void FormatPhoneNumber_InvalidLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.FormatPhoneNumber(digits));
    }

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.StartsWith("Dear Mr.", result);
        Assert.EndsWith("Smith,", result);
        Assert.AreEqual("Dear Mr. Smith,", result);
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_UsesProvidedTitle()
    {
        var result = _formatter.BuildGreeting("Johnson", "Dr.");

        Assert.StartsWith("Dear Dr.", result);
        Assert.EndsWith("Johnson,", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_InvalidName_ThrowsArgumentException(string? name)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.BuildGreeting(name!));
    }

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseHyphenated()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_StripsAndHyphenates()
    {
        var result = _formatter.GenerateSlug("  My Great Post!!! ");

        Assert.StartsWith("my", result);
        Assert.EndsWith("post", result);
        Assert.MatchesRegex(@"^[a-z0-9]+(-[a-z0-9]+)*$", result);
    }

    [TestMethod]
    [DataRow("A & B", "a-b")]
    [DataRow("---leading---", "leading")]
    [DataRow("UPPERCASE", "uppercase")]
    public void GenerateSlug_VariousInputs_ReturnsExpectedSlug(string title, string expected)
    {
        var result = _formatter.GenerateSlug(title);

        Assert.AreEqual(expected, result);
        Assert.MatchesRegex(@"^[a-z0-9]", result);
    }

    [TestMethod]
    public void FormatCurrency_PositiveAmount_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(19.99m);

        Assert.StartsWith("$", result);
        Assert.EndsWith("99", result);
        Assert.AreEqual("$19.99", result);
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(100m, "€");

        Assert.StartsWith("€", result);
        Assert.AreEqual("€100.00", result);
    }

    [TestMethod]
    public void FormatCurrency_ZeroAmount_FormatsWithTwoDecimals()
    {
        var result = _formatter.FormatCurrency(0m);

        Assert.EndsWith(".00", result);
        Assert.AreEqual("$0.00", result);
    }

    [TestMethod]
    public void FormatCurrency_NegativeAmount_ContainsMinusSign()
    {
        var result = _formatter.FormatCurrency(-5.5m);

        Assert.StartsWith("$-", result);
        Assert.EndsWith(".50", result);
    }
}

